import{IniciarMenuVertical}from"./menu-vertical.js";import{verificarUsuarioExiste}from"../main.js";function sanitizarHTML(r){var t=document.createElement("div");return t.textContent=r,t.innerHTML}verificarUsuarioExiste();class criarProduto{constructor(r,t,e,o){this.id=r,this.nome=t,this.imagem=o,this.preco=e}devolverCard(){var r=document.createElement("div");return r.innerHTML=` <div class='card' data-id="${this.id}">
                                            <img src='${this.imagem}'>
                                            <div class='card-body'>
                                                <h5 class='card-title'>${sanitizarHTML(this.nome)}</h5>
                                                <h3>${sanitizarHTML(this.preco)}</h3>
                                            </div>
                                                <div class="botao-remover">
                                                    <button class="botao-remover__botao">
                                                        Remover
                                                    </button>
                                                </div>
                                        </div>`,r}}async function criarCardFavoritos(){let o=localStorage.getItem("meusFavoritos");var r,t=document.querySelector(".produtos-favoritados");let a=JSON.parse(o)||[];t.innerHTML="",a.length<1&&(t.innerHTML='<p class="text-light text-center nenhum-favorito mb-0">Nenhum produto favoritado</p>');for(r of a){var e=await(async r=>{try{var e=await(await fetch("./../produtos.json")).json();let t=Number(String(r).replace(/\D/g,""));return e.find(r=>Number(r.id)===t)}catch(r){console.error("Erro ao filtrar dados:",r)}})(r),e=new criarProduto(e.id,e.nome,e.preco,e.imagem).devolverCard();t.appendChild(e)}document.querySelectorAll(".card").forEach(e=>{e.querySelectorAll(".botao-remover").forEach(r=>{r.addEventListener("click",r=>{r.stopPropagation(),e.style.filter="opacity(0)",setTimeout(function(){let t=e.dataset.id;var r=a.filter(r=>String(r)!==String(t));o=r,localStorage.setItem("meusFavoritos",JSON.stringify(o)),criarCardFavoritos()},500)})})}),document.querySelector("#seta-voltar-home").addEventListener("click",()=>{window.location.href="index.html"})}export{criarCardFavoritos};